import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class SpacingAroundRangeUntilOperatorRuleTest {
    private val spacingAroundRangeOperatorRuleAssertThat = assertThatRule { SpacingAroundRangeOperatorRule() }

    @Test
    fun `Given a rangeUntil expression`() {
        val code =
            """
            val foo1 = (1..<12 step 2).last
            val foo2 = (1..< 12 step 2).last
            val foo3 = (1 ..< 12 step 2).last
            val foo4 = (1 ..<12 step 2).last
            """.trimIndent()
        val formattedCode =
            """
            val foo1 = (1..<12 step 2).last
            val foo2 = (1..<12 step 2).last
            val foo3 = (1..<12 step 2).last
            val foo4 = (1..<12 step 2).last
            """.trimIndent()
        spacingAroundRangeOperatorRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(2, 17, "Unexpected spacing after \"..<\""),
                LintViolation(3, 15, "Unexpected spacing around \"..<\""),
                LintViolation(4, 14, "Unexpected spacing before \"..<\""),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a rangeUntil in a for loop`() {
        val code =
            """
            fun foo() {
                for (i in 1..<4) print(i)
                for (i in 1..< 4) print(i)
                for (i in 1 ..< 4) print(i)
                for (i in 1 ..<4) print(i)
            }
            """.trimIndent()
        val formattedCode =
            """
            fun foo() {
                for (i in 1..<4) print(i)
                for (i in 1..<4) print(i)
                for (i in 1..<4) print(i)
                for (i in 1..<4) print(i)
            }
            """.trimIndent()
        spacingAroundRangeOperatorRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(3, 19, "Unexpected spacing after \"..<\""),
                LintViolation(4, 17, "Unexpected spacing around \"..<\""),
                LintViolation(5, 16, "Unexpected spacing before \"..<\""),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given a rangeUntil in a when expression`() {
        val code =
            """
            fun foo(int: Int): String =
                when (int) {
                    in 10..<20 -> "A"
                    in 20..< 30 -> "B"
                    in 30 ..< 40 -> "C"
                    in 40 ..<50 -> "D"
                    else -> "unknown"
                }
            """.trimIndent()
        val formattedCode =
            """
            fun foo(int: Int): String =
                when (int) {
                    in 10..<20 -> "A"
                    in 20..<30 -> "B"
                    in 30..<40 -> "C"
                    in 40..<50 -> "D"
                    else -> "unknown"
                }
            """.trimIndent()
        spacingAroundRangeOperatorRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(4, 17, "Unexpected spacing after \"..<\""),
                LintViolation(5, 15, "Unexpected spacing around \"..<\""),
                LintViolation(6, 14, "Unexpected spacing before \"..<\""),
            ).isFormattedAs(formattedCode)
    }
}
"}

